import { difficulty } from './stores/difficulty'
import { gamePaused } from './stores/game'
import { gameStore } from './stores/domainGame'
import { cursor } from './stores/cursor'
import { timer } from './stores/timer'
import { hints } from './stores/hints'
import { candidates } from './stores/candidates'
import { notes } from './stores/notes'

function resetUiState() {
	cursor.reset()
	timer.reset()
	hints.reset()
	if (notes.reset) notes.reset()
	if (candidates.reset) candidates.reset()
}

/**
 * Start new game with a generated sudoku
 *
 * @param {('veryeasy' | 'easy' | 'medium' | 'hard')} diff - Difficulty
 */
export function startNew(diff) {
	difficulty.set(diff)
	gameStore.startGenerated(diff)
	resetUiState()

	location.hash = ''
}

/**
 * Start new game with a custom sudoku
 *
 * @param {string} sencode - Sencode to decode
 */
export function startCustom(sencode) {
	difficulty.setCustom()
	gameStore.startFromSencode(sencode)
	resetUiState()
}

export function undoMove() {
	const changed = gameStore.undo()
	if (changed) {
		if (notes.reset) notes.reset()
	}
	return changed
}

export function redoMove() {
	const changed = gameStore.redo()
	if (changed) {
		if (notes.reset) notes.reset()
	}
	return changed
}

export function startExplore() {
	return gameStore.startExplore()
}

export function commitExplore() {
	return gameStore.commitExplore()
}

export function abandonExplore() {
	return gameStore.abandonExplore()
}

/**
 * Pause the game
 */
export function pauseGame() {
	timer.stop()
	gamePaused.set(true)
}

/**
 * Resume (un-pause) the game
 */
export function resumeGame() {
	timer.start()
	gamePaused.set(false)
}

export default {
	startNew,
	startCustom,
	undo: undoMove,
	redo: redoMove,
	startExplore,
	commitExplore,
	abandonExplore,
	pause: pauseGame,
	resume: resumeGame,
}
